<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0;font-family:sans-serif;}
  body,html{height:100%;background:#222;color:#eee;}
  #desktop{position:relative;width:100%;height:100%;}
  #taskbar{
    position:absolute;bottom:0;left:0;height:40px;background:#111;
    display:flex;align-items:center;padding-left:10px;border-top:1px solid #444;
  }
  .launcher{
    width:32px;height:32px;margin-right:8px;background:#333;border-radius:4px;
    display:flex;align-items:center;justify-content:center;color:#fff;
    cursor:pointer;font-size:18px;user-select:none;
  }
  .window{
    position:absolute;top:50px;left:50px;width:400px;height:300px;
    background:#333;border-radius:6px;box-shadow:0 2px 10px rgba(0,0,0,.5);
    display:flex;flex-direction:column;overflow:hidden;
  }
  .win-header{
    height:30px;background:#222;color:#fff;padding:0 8px;
    display:flex;align-items:center;justify-content:space-between;
    cursor:move;font-size:14px;
  }
  .win-close{cursor:pointer;}
  .win-body{flex:1;overflow:auto;padding:10px;background:#444;}
  /* Files app */
  #files-path{font-family:monospace;margin-bottom:5px;}
  .fs-item{
    padding:2px 4px;border-radius:3px;cursor:pointer;
  }
  .fs-item:hover{background:#555;}
  /* Notepad */
  #tabs{display:flex;height:30px;background:#222;color:#fff;font-size:14px;}
  .tab{
    padding:0 10px;line-height:30px;cursor:pointer;border-right:1px solid #444;
  }
  .tab.active{background:#555;}
  #new-tab{margin-left:auto;padding:0 8px;background:none;border:none;color:#fff;cursor:pointer;}
  textarea#editor{
    width:100%;height:calc(100% - 30px);border:none;background:#222;color:#eee;font-family:monospace;
    resize:none;padding:10px;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <div class="launcher" id="open-files">📁</div>
    <div class="launcher" id="open-notepad">📝</div>
  </div>

  <!-- Files Window -->
  <div class="window" id="files-window" style="display:none;">
    <div class="win-header">
      <span>Files</span><span class="win-close">&times;</span>
    </div>
    <div class="win-body">
      <div id="files-path">/</div>
      <button id="files-up">Up</button>
      <div id="file-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div class="window" id="notepad-window" style="display:none;">
    <div class="win-header">
      <span>Notepad</span><span class="win-close">&times;</span>
    </div>
    <div class="win-body">
      <div id="tabs"></div>
      <textarea id="editor"></textarea>
    </div>
  </div>
</div>

<script>
/* ---------- Filesystem Data ----------
   Simple static representation */
const fs = {
  '/': {bin:true, etc:true, home:true, usr:true, var:true},
  '/home': {user:true},
  '/home/user': {Documents:true, Downloads:true, Pictures:true}
};
/* Helper to get entries of a path */
function listEntries(path){
  const dir = fs[path] || {};
  return Object.keys(dir).map(name=>({name, isDir:dir[name]}));
}

/* ---------- Files App ----------
   State */
let currentPath = '/';
const filesWindow=document.getElementById('files-window');
const fileList=document.getElementById('file-list');
const pathDisplay=document.getElementById('files-path');
const upBtn=document.getElementById('files-up');

/* Render list */
function renderFiles(){
  pathDisplay.textContent=currentPath;
  fileList.innerHTML='';
  const entries=listEntries(currentPath);
  entries.forEach(entry=>{
    const div=document.createElement('div');
    div.className='fs-item';
    div.textContent=entry.name + (entry.isDir?'/':'');
    if(entry.isDir){
      div.addEventListener('dblclick',()=>{
        currentPath+=currentPath.endsWith('/')?entry.name:('/'+entry.name);
        renderFiles();
      });
    }
    fileList.appendChild(div);
  });
}

/* Up navigation */
upBtn.onclick=()=>{if(currentPath!=='/') {currentPath=currentPath.split('/').slice(0,-2).join('/')||'/';renderFiles();}};

/* ---------- Notepad ----------
   State & Persistence */
const notepadWindow=document.getElementById('notepad-window');
const tabsContainer=document.getElementById('tabs');
const editor=document.getElementById('editor');
let tabs=[]; // array of {id, title, content}
let activeTab=null;
const STORAGE_KEY='miniDesktopNotepadTabs';

/* Load from localStorage */
function loadTabs(){
  const data=localStorage.getItem(STORAGE_KEY);
  if(data){tabs=JSON.parse(data);}
  else{tabs=[{id:Date.now(),title:'Untitled',content:''}];}
  activeTab=tabs[0];
}

/* Save to localStorage */
function saveTabs(){localStorage.setItem(STORAGE_KEY,JSON.stringify(tabs));}

/* Render tabs */
function renderTabs(){
  tabsContainer.innerHTML='';
  tabs.forEach(tab=>{
    const div=document.createElement('div');
    div.className='tab'+(tab===activeTab?' active':'');
    div.textContent=tab.title;
    div.onclick=()=>{switchTab(tab.id);};
    tabsContainer.appendChild(div);
  });
  // New tab button
  const newBtn=document.createElement('button');newBtn.id='new-tab';newBtn.textContent='+';
  newBtn.onclick=addNewTab;tabsContainer.appendChild(newBtn);
}

/* Switch active tab */
function switchTab(id){
  const t=tabs.find(t=>t.id===id);if(!t)return;
  activeTab=t;
  editor.value=activeTab.content;
  renderTabs();
}

/* Add new tab */
function addNewTab(){
  const id=Date.now();const newTab={id,title:'Untitled',content:''};
  tabs.push(newTab);
  switchTab(id);
  saveTabs();
}

/* Update content on change */
editor.addEventListener('input',()=>{
  if(activeTab){activeTab.content=editor.value;saveTabs();}
});

/* ---------- Window Controls ----------
   Openers */
document.getElementById('open-files').onclick=()=>{filesWindow.style.display='flex';renderFiles();};
document.getElementById('open-notepad').onclick=()=>{notepadWindow.style.display='flex';loadTabs();renderTabs();editor.value=activeTab.content;};

/* Close buttons */
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.onclick=e=>{e.target.parentNode.parentNode.style.display='none';};
});

/* ---------- Dragging ----------
   Basic drag for windows */
function makeDraggable(win){
  const header=win.querySelector('.win-header');
  let offsetX,offsetY;
  header.onmousedown=e=>{
    offsetX=e.clientX-win.offsetLeft;
    offsetY=e.clientY-win.offsetTop;
    document.onmousemove=move;
    document.onmouseup=stop;
  };
  function move(e){win.style.left=(e.clientX-offsetX)+'px';win.style.top=(e.clientY-offsetY)+'px';}
  function stop(){document.onmousemove=null;document.onmouseup=null;}
}
makeDraggable(filesWindow);makeDraggable(notepadWindow);
</script>
</body>
</html>
